// ===== DATA PARSING =====
const tickerRaw    = $('Fetch BTC').first().json;
const signalsRaw   = $('Read Signals').first().json;
const outcomesRaw  = $('Read Outcomes').first().json;
const adaptRaw     = $('Read Adaptive Params').first().json;
let ethTickerRaw = {};
try { ethTickerRaw = $('Fetch ETH Ticker').first().json; } catch(e) {}
let ethSignalsRaw = {}, ethOutcomesRaw = {}, ethAdaptRaw = {};
try { ethSignalsRaw  = $('Read ETH Signals').first().json;  } catch(e) {}
try { ethOutcomesRaw = $('Read ETH Outcomes').first().json; } catch(e) {}
try { ethAdaptRaw    = $('Read ETH Adaptive').first().json; } catch(e) {}

// ===== BTC TICKER =====
const r       = (tickerRaw && tickerRaw.result) ? tickerRaw.result : {};
const k       = Object.keys(r)[0];
const t       = r[k] || {};
const btcPrice  = t.c ? parseFloat(t.c[0]) : 0;
const btcOpen   = t.o ? parseFloat(t.o)    : btcPrice;
const btcHigh   = t.h ? parseFloat(t.h[1]) : btcPrice;
const btcLow    = t.l ? parseFloat(t.l[1]) : btcPrice;
const btcVwap   = t.p ? parseFloat(t.p[1]) : btcPrice;
const btcVol    = t.v ? parseFloat(t.v[1]) : 0;
const btcVolUSD = Math.round(btcVol * btcVwap / 1e6);
const btcTrades = t.t ? t.t[1] : 0;
const btcBid    = t.b ? parseFloat(t.b[0]) : btcPrice;
const btcAsk    = t.a ? parseFloat(t.a[0]) : btcPrice;
const btcSpread = Math.abs(btcAsk - btcBid).toFixed(2);
const btcChg    = btcOpen > 0 ? ((btcPrice - btcOpen) / btcOpen) * 100 : 0;
const btcChgStr = (btcChg >= 0 ? '+' : '') + btcChg.toFixed(2) + '%';
const btcRangePos = btcHigh > btcLow ? Math.round(((btcPrice - btcLow) / (btcHigh - btcLow)) * 100) : 50;

// ===== ETH TICKER =====
const re      = (ethTickerRaw && ethTickerRaw.result) ? ethTickerRaw.result : {};
const ke      = Object.keys(re)[0];
const te      = re[ke] || {};
const ethPrice  = te.c ? parseFloat(te.c[0]) : 0;
const ethOpen   = te.o ? parseFloat(te.o)    : ethPrice;
const ethHigh   = te.h ? parseFloat(te.h[1]) : ethPrice;
const ethLow    = te.l ? parseFloat(te.l[1]) : ethPrice;
const ethVwap   = te.p ? parseFloat(te.p[1]) : ethPrice;
const ethVol    = te.v ? parseFloat(te.v[1]) : 0;
const ethVolUSD = Math.round(ethVol * ethVwap / 1e6);
const ethTrades = te.t ? te.t[1] : 0;
const ethBid    = te.b ? parseFloat(te.b[0]) : ethPrice;
const ethAsk    = te.a ? parseFloat(te.a[0]) : ethPrice;
const ethSpread = Math.abs(ethAsk - ethBid).toFixed(2);
const ethChg    = ethOpen > 0 ? ((ethPrice - ethOpen) / ethOpen) * 100 : 0;
const ethChgStr = (ethChg >= 0 ? '+' : '') + ethChg.toFixed(2) + '%';
const ethRangePos = ethHigh > ethLow ? Math.round(((ethPrice - ethLow) / (ethHigh - ethLow)) * 100) : 50;

// ===== SIGNAL PARSER =====
const parseSignals = (raw) => {
  const mems = (raw && raw.memories) ? raw.memories : [];
  const sigs = [];
  for (const m of mems.slice(0, 10)) {
    const c    = m.content || '';
    const dir  = (c.match(/TRADE SIGNAL[^:]*:\s*(BUY|SELL|WAIT)/) || [])[1];
    const px   = (c.match(/@\s*\$(\d+)/)                           || [])[1];
    const conf = (c.match(/Conf[idence]*[:\s]+([\d.]+)%/)          || [])[1];
    const rsi  = (c.match(/RSI[:\s]+([\d.]+)/)                     || [])[1];
    const reg  = (c.match(/Regime[:\s]+(\S+?)(?:\s|$|\|)/)         || [])[1];
    const quor = (c.match(/Quorum[:\s]+(\d+)/)                     || [])[1];
    const nts  = (c.match(/No.?Trade[:\s]+([\d.]+)/)               || [])[1];
    const ts   = m.created_at ? m.created_at.slice(11, 16) : '?';
    if (!dir) continue;
    sigs.push({ dir, px: px||'?', conf: conf||'?', rsi: rsi||'?', reg: reg||'?', quor: quor||'?', nts: nts||'?', ts });
  }
  return sigs;
};

// ===== OUTCOME PARSER =====
const parseOutcomes = (raw) => {
  const mems = (raw && raw.memories) ? raw.memories : [];
  let hr = -1, correct = 0, incorrect = 0, total = 0, avgConf = 0;
  for (const o of mems) {
    const c  = o.content || '';
    const hm = (c.match(/Hit Rate[:\s]+([\d.]+)%/) || [])[1];
    if (hm) {
      hr        = parseInt(hm);
      correct   = parseInt((c.match(/Correct[:\s]+(\d+)/)              || [])[1] || 0);
      incorrect = parseInt((c.match(/Incorrect[:\s]+(\d+)/)            || [])[1] || 0);
      total     = correct + incorrect;
      avgConf   = parseFloat((c.match(/Avg Confidence[:\s]+([\d.]+)%/) || [])[1] || 0);
      break;
    }
  }
  return { hr, correct, incorrect, total, avgConf };
};

// ===== ADAPTIVE PARAMS PARSER =====
const parseAdapt = (raw, key) => {
  const mems = (raw && raw.memories) ? raw.memories : [];
  const mem  = mems.find(m => (m.content||'').includes(key));
  const ac   = mem ? (mem.content || '') : '';
  let minConf = 60, buyMult = 1.0, sellMult = 1.0, adaptiveActive = false, hrWilson = null, brier = null, buyHRWilson = null, sellHRWilson = null;
  let buyHR = null, sellHR = null, gradeable = 0, dataQuality = 'INSUFFICIENT';
  if (ac) {
    const mcM = ac.match(/minConf:(\d+)/);
    const bmM = ac.match(/buyMult:([\d.]+)/);
    const smM = ac.match(/sellMult:([\d.]+)/);
    const bhM = ac.match(/buyHR:(\d+)%/);
    const shM = ac.match(/sellHR:(\d+)%/);
    const grM = ac.match(/gradeable:(\d+)/);
    const dqM = ac.match(/dataQuality:(\w+)/);
    if (grM) gradeable = parseInt(grM[1]);
    if (dqM) dataQuality = dqM[1];
    if (mcM && gradeable >= 10) { minConf = parseInt(mcM[1]); adaptiveActive = true; }
    const wilsonM = ac.match(/hitRateWilson:(\d+)%/);
    const brierM  = ac.match(/brier:([\d.]+)/);
    const buyHRWilsonM  = ac.match(/buyHRWilson:(\d+)%/);
    const sellHRWilsonM = ac.match(/sellHRWilson:(\d+)%/);
    if (wilsonM)        hrWilson = parseInt(wilsonM[1]);
    if (brierM && brierM[1] !== "NA") brier = parseFloat(brierM[1]);
    if (buyHRWilsonM)   buyHRWilson  = parseInt(buyHRWilsonM[1]);
    if (sellHRWilsonM)  sellHRWilson = parseInt(sellHRWilsonM[1]);
    if (bmM && gradeable >= 8)  buyMult  = parseFloat(bmM[1]);
    if (smM && gradeable >= 8)  sellMult = parseFloat(smM[1]);
    if (bhM) buyHR  = parseInt(bhM[1]);
    if (shM) sellHR = parseInt(shM[1]);
  }
  return { minConf, buyMult, sellMult, adaptiveActive, buyHR, sellHR, gradeable, dataQuality, hrWilson, brier, buyHRWilson, sellHRWilson };
};

// ===== WILSON CI =====
const wilsonCI = (correct, total) => {
  if (total < 2) return { lo: 0, hi: 100 };
  const z = 1.96, p = correct / total, z2 = z * z;
  const denom  = 1 + z2 / total;
  const center = (p + z2 / (2 * total)) / denom;
  const margin = (z / denom) * Math.sqrt(p * (1 - p) / total + z2 / (4 * total * total));
  return { lo: Math.max(0, Math.round((center - margin) * 100)), hi: Math.min(100, Math.round((center + margin) * 100)) };
};

// ===== DATA FOR EACH COIN =====
const btcSigs  = parseSignals(signalsRaw);
const btcOut   = parseOutcomes(outcomesRaw);
const btcAdapt = parseAdapt(adaptRaw, 'ADAPTIVE_PARAMS');
const btcCI    = wilsonCI(btcOut.correct, btcOut.total);

const ethSigs  = parseSignals(ethSignalsRaw);
const ethOut   = parseOutcomes(ethOutcomesRaw);
const ethAdapt = parseAdapt(ethAdaptRaw, 'ETH_ADAPT_PARAMS');
const ethCI    = wilsonCI(ethOut.correct, ethOut.total);

// ===== HELPERS =====
const fmt    = n => Math.round(n).toLocaleString('en-US');
const fmtK   = n => n >= 1000 ? (n / 1000).toFixed(1) + 'K' : String(n);
const dCol   = d => d === 'BUY' ? '#00d97e' : d === 'SELL' ? '#ff4d6d' : '#8892a4';
const dBg    = d => d === 'BUY' ? 'rgba(0,217,126,.13)' : d === 'SELL' ? 'rgba(255,77,109,.13)' : 'rgba(136,146,164,.09)';
const dArrow = d => d === 'BUY' ? '&#9650;' : d === 'SELL' ? '&#9660;' : '&#9654;';
const hCol   = hr => hr >= 55 ? '#00d97e' : hr >= 0 ? '#ff4d6d' : '#8892a4';

const regLabel = reg => {
  const m = { 'BULL_TREND_STRONG':'Bull Strong','BULL_TREND_WEAK':'Bull Weak','BEAR_TREND_STRONG':'Bear Strong','BEAR_TREND_WEAK':'Bear Weak','RANGING':'Ranging','CHOPPY':'Choppy','EXTREME_CAUTION':'Caution','BREAKOUT':'Breakout','ACCUMULATION':'Accum.','DISTRIBUTION':'Distrib.' };
  return m[reg] || reg || '&mdash;';
};
const regColor = reg => {
  if (!reg) return '#8892a4';
  if (reg.includes('BULL') || reg === 'BREAKOUT' || reg === 'ACCUMULATION') return '#00d97e';
  if (reg.includes('BEAR') || reg === 'DISTRIBUTION') return '#ff4d6d';
  if (reg === 'EXTREME_CAUTION') return '#f59e0b';
  return '#8892a4';
};
const gaugeArc = pct => {
  const rr = 54, cx = 70, cy = 70;
  const end = Math.PI + (Math.min(pct,100) / 100) * Math.PI;
  return `M 16.0 70.0 A 54 54 0 ${pct > 50 ? 1 : 0} 1 ${(cx + rr * Math.cos(end)).toFixed(1)} ${(cy + rr * Math.sin(end)).toFixed(1)}`;
};

// ===== COIN PANEL BUILDER =====
const buildPanel = (coin, price, open, high, low, vwap, volUSD, trades, bid, ask, spread, chg, chgStr, rangePos, sigs, out, adapt, ci) => {
  const last   = sigs[0] || {};
  const confNum = parseFloat(last.conf) || 0;
  const pCol   = chg >= 0 ? '#00d97e' : '#ff4d6d';
  const hc     = hCol(out.hr);
  const buyCnt = sigs.filter(s => s.dir === 'BUY').length;
  const sellCnt= sigs.filter(s => s.dir === 'SELL').length;
  const waitCnt= sigs.filter(s => s.dir === 'WAIT').length;

  const MILESTONE_BASIC = 30, MILESTONE_ADAPTIVE = 100;
  const progressPct   = Math.min(100, Math.round(adapt.gradeable / MILESTONE_ADAPTIVE * 100));
  const progressLabel = adapt.gradeable >= MILESTONE_ADAPTIVE ? 'ADAPTIVE VALIDATED' : adapt.gradeable >= MILESTONE_BASIC ? 'BUILDING EDGE' : 'ACCUMULATING';
  const progressCol   = adapt.gradeable >= MILESTONE_ADAPTIVE ? '#00d97e' : adapt.gradeable >= MILESTONE_BASIC ? '#f59e0b' : '#8892a4';
  const nextMilestone = adapt.gradeable < MILESTONE_BASIC ? MILESTONE_BASIC : adapt.gradeable < MILESTONE_ADAPTIVE ? MILESTONE_ADAPTIVE : 200;
  const nextLabel     = adapt.gradeable < MILESTONE_BASIC ? 'basic edge' : adapt.gradeable < MILESTONE_ADAPTIVE ? 'adaptive validated' : 'full foundation';

  const driftRows = [
    { label:'Min Conf', val:adapt.minConf, def:60, unit:'%' },
    { label:'BUY Mult', val:adapt.buyMult, def:1.0, unit:'�' },
    { label:'SELL Mult',val:adapt.sellMult,def:1.0, unit:'�' },
  ].map(r => {
    const drifted = r.val !== r.def;
    const dir = r.val > r.def ? '?' : r.val < r.def ? '?' : '-';
    const col = drifted ? (r.val > r.def ? '#00d97e' : '#f59e0b') : '#8892a4';
    const live = adapt.adaptiveActive ? (drifted ? `<span style="color:${col}">${dir} ${r.val}${r.unit}</span>` : `<span style="color:#8892a4">- ${r.val}${r.unit}</span>`) : `<span style="color:#4e617a">need 10 signals</span>`;
    return `<tr><td>${r.label}</td><td style="color:#4e617a;text-align:center">${r.def}${r.unit}</td><td style="text-align:right;font-weight:700">${live}</td></tr>`;
  }).join('');

  const sigRows = sigs.map((s, i) => `
<tr class="sig-row" style="animation-delay:${i * 0.04}s">
  <td class="ts">${s.ts}</td>
  <td><span class="dir-chip" style="color:${dCol(s.dir)};background:${dBg(s.dir)}">${dArrow(s.dir)}&nbsp;${s.dir||'WAIT'}</span></td>
  <td class="mono">$${parseInt(s.px||0).toLocaleString('en-US')}</td>
  <td><div class="cpill"><div class="cfill" style="width:${s.conf}%;background:${dCol(s.dir)}40"></div><div class="cfill-glow" style="width:${s.conf}%;background:${dCol(s.dir)}"></div><span class="cnum">${s.conf}%</span></div></td>
  <td class="mono">${s.rsi}</td>
  <td style="color:${regColor(s.reg)};font-weight:600">${regLabel(s.reg)}</td>
</tr>`).join('') || `<tr><td colspan="6" class="empty-td">No signals yet - workflow runs every 5 min</td></tr>`;

  return `
<!-- ========== ${coin} PANEL ========== -->
<div class="kpi-grid mb12">
  <div class="card price-card" style="animation:priceGlow_${coin} 4s ease-in-out infinite">
    <div class="gblob" style="background:${pCol}"></div>
    <div class="kp">
      <div class="kp-lbl">${coin} / USD</div>
      <div class="kp-val" style="color:${pCol}">$${fmt(price)}<span class="delta" style="color:${pCol}">${chgStr}</span></div>
      <div class="kp-sub">Open&nbsp;<strong>$${fmt(open)}</strong>&nbsp;|&nbsp;VWAP&nbsp;<strong>$${fmt(vwap)}</strong></div>
    </div>
  </div>
  <div class="card">
    <div class="gblob" style="background:${dCol(last.dir||'WAIT')}"></div>
    <div class="kp">
      <div class="kp-lbl">Current Signal</div>
      <div class="kp-val" style="font-size:1.7rem;display:flex;align-items:center;gap:8px;color:${dCol(last.dir||'WAIT')}">
        <span style="font-size:1.4rem">${dArrow(last.dir||'WAIT')}</span><span>${last.dir||'WAIT'}</span>
      </div>
      <div class="kp-sub">Conf:&nbsp;<strong style="color:${dCol(last.dir||'WAIT')}">${last.conf||'?'}%</strong>&nbsp;|&nbsp;${last.ts||'&mdash;'}&nbsp;UTC</div>
    </div>
  </div>
  <div class="card">
    <div class="kp">
      <div class="kp-lbl">Hit Rate</div>
      <div class="kp-val" style="color:${hc}">${out.hr >= 0 ? out.hr + '%' : 'N/A'}</div>
      <div class="kp-sub">
        ${out.total > 0 ? `<span style="color:var(--grn)">${out.correct}&nbsp;W</span>&nbsp;/&nbsp;<span style="color:var(--red)">${out.incorrect}&nbsp;L</span>&nbsp;of&nbsp;${out.total}` : '<em>Accumulating...</em>'}
        ${out.total >= 2 ? `&nbsp;|&nbsp;<span style="color:var(--mut)">CI: ${ci.lo}-${ci.hi}%</span>` : ''}
      </div>
    </div>
  </div>
  <div class="card">
    <div class="kp">
      <div class="kp-lbl">Market Regime</div>
      <div class="kp-val" style="font-size:1.05rem;margin-top:4px;line-height:1.5;font-weight:800;color:${regColor(last.reg||'')}">${regLabel(last.reg||'')}</div>
      <div class="kp-sub">${last.quor && last.quor !== '?' ? 'Quorum:&nbsp;<strong>' + last.quor + '/10</strong>&nbsp;families' : 'Market structure class'}</div>
    </div>
  </div>
</div>

<div class="card range-card mb12">
  <div class="range-lbl">24H Price Range</div>
  <div class="rbar-wrap">
    <div class="rbar-fill" style="width:${rangePos}%"></div>
    <div class="rbar-thumb" style="left:${rangePos}%"></div>
  </div>
  <div class="rbar-labels">
    <span style="color:var(--red);font-weight:700">Low&nbsp;$${fmt(low)}</span>
    <span style="color:var(--mut2)">$${fmt(price)}&nbsp;(${rangePos}%)</span>
    <span style="color:var(--grn);font-weight:700">High&nbsp;$${fmt(high)}</span>
  </div>
  <div class="rmeta">
    <span class="rmeta-item"><span class="rmdot"></span>Vol 24H:&nbsp;<strong>$${volUSD}M</strong></span>
    <span class="rmeta-item"><span class="rmdot"></span>Trades:&nbsp;<strong>${fmtK(trades)}</strong></span>
    <span class="rmeta-item"><span class="rmdot"></span>Spread:&nbsp;<strong>$${spread}</strong></span>
    <span class="rmeta-item"><span class="rmdot"></span>Bid:&nbsp;<strong>$${fmt(bid)}</strong></span>
    <span class="rmeta-item"><span class="rmdot"></span>Ask:&nbsp;<strong>$${fmt(ask)}</strong></span>
  </div>
</div>

<div class="mid-grid">
  <div class="card dir-card">
    <div class="kp-lbl">Signal Direction &amp; Momentum</div>
    <div class="dir-big">
      <div class="dir-icon" style="color:${dCol(last.dir||'WAIT')};text-shadow:0 0 30px ${dCol(last.dir||'WAIT')}">${dArrow(last.dir||'WAIT')}</div>
      <div class="dir-txt" style="color:${dCol(last.dir||'WAIT')}">${last.dir||'WAIT'}</div>
      <div class="dir-meta">${last.rsi && last.rsi !== '?' ? 'RSI ' + last.rsi + ' | ' : ''}${last.nts && last.nts !== '?' ? 'No-Trade ' + last.nts + '%' : 'Awaiting scan...'}</div>
    </div>
    <div class="dir-pills">
      <div class="dir-pill"><div class="dp-lbl">Buy</div><div class="dp-val" style="color:var(--grn)">${buyCnt}</div></div>
      <div class="dir-pill"><div class="dp-lbl">Sell</div><div class="dp-val" style="color:var(--red)">${sellCnt}</div></div>
      <div class="dir-pill"><div class="dp-lbl">Wait</div><div class="dp-val" style="color:var(--mut2)">${waitCnt}</div></div>
    </div>
  </div>
  <div class="card gauge-card">
    <div class="kp-lbl">Signal Confidence</div>
    <div class="gauge-wrap">
      <svg width="140" height="80" viewBox="0 0 140 80">
        <path d="M 16.0 70.0 A 54 54 0 0 1 124.0 70.0" stroke="rgba(30,46,70,.9)" stroke-width="10" fill="none" stroke-linecap="round"/>
        <path d="${gaugeArc(confNum)}" stroke="${confNum>=adapt.minConf?dCol(last.dir||'WAIT'):'var(--mut)'}" stroke-width="10" fill="none" stroke-linecap="round" style="filter:drop-shadow(0 0 7px ${confNum>=adapt.minConf?dCol(last.dir||'WAIT'):'transparent'})"/>
        <path d="${gaugeArc(adapt.minConf)}" stroke="var(--ylw)" stroke-width="2" fill="none" stroke-dasharray="4 9999"/>
      </svg>
      <div class="gauge-num" style="color:${confNum>=adapt.minConf?dCol(last.dir||'WAIT'):'var(--mut2)'}">${last.conf||'?'}%</div>
    </div>
    <div class="gauge-caption">${confNum>=adapt.minConf?'<span style="color:var(--grn);font-weight:700">&#10003; Above threshold</span>':confNum>0?'<span style="color:var(--red)">&#10007; WAIT forced</span>':'<span style="color:var(--mut)">Awaiting first scan...</span>'}</div>
    <div class="gauge-threshold"><span style="color:var(--mut)">Min to trade:</span><strong style="color:var(--ylw)">${adapt.minConf}%</strong>
      ${adapt.adaptiveActive ? '<span style="background:rgba(0,217,126,.1);border:1px solid rgba(0,217,126,.3);color:var(--grn);border-radius:5px;padding:2px 7px;font-size:.62rem;font-weight:700;margin-left:6px">&#9679; ADAPTIVE</span>' : '<span style="background:rgba(78,97,122,.1);border:1px solid rgba(78,97,122,.3);color:var(--mut);border-radius:5px;padding:2px 7px;font-size:.62rem;margin-left:6px">DEFAULT</span>'}
    </div>
  </div>
  <div class="card ring-card">
    <div class="kp-lbl">Performance Ring</div>
    <div class="ring-wrap">
      <svg width="110" height="110" viewBox="0 0 110 110">
        <circle cx="55" cy="55" r="44" fill="none" stroke="rgba(30,46,70,.9)" stroke-width="9"/>
        <circle cx="55" cy="55" r="44" fill="none" stroke="${hc}" stroke-width="9" stroke-linecap="round"
          stroke-dasharray="${out.hr>=0?((out.hr/100)*276.5).toFixed(1)+' 276.5':'0 276.5'}"
          style="filter:drop-shadow(0 0 7px ${hc})"/>
      </svg>
      <div class="ring-num" style="color:${hc}">${out.hr>=0?out.hr+'%':'N/A'}</div>
    </div>
    <div class="ring-lbl"><span style="color:var(--ylw)">Target: 55%+</span>${out.hr>=55?'&nbsp;<span style="color:var(--grn);font-weight:700">&#10003;</span>':''}</div>
    <div class="dir-split">
      <div class="ds-pill"><div class="ds-lbl">BUY acc.</div><div class="ds-val" style="color:${adapt.buyHR!==null?(adapt.buyHR>=55?'var(--grn)':'var(--red)'):'var(--mut)'}">${adapt.buyHR!==null?adapt.buyHR+'%':'N/A'}</div></div>
      <div class="ds-pill"><div class="ds-lbl">SELL acc.</div><div class="ds-val" style="color:${adapt.sellHR!==null?(adapt.sellHR>=55?'var(--grn)':'var(--red)'):'var(--mut)'}">${adapt.sellHR!==null?adapt.sellHR+'%':'N/A'}</div></div>
    </div>
  </div>
</div>

<div class="analytics-grid">
  <div class="card analytics-card">
    <div class="an-hdr"><span>Foundation Progress</span><span style="color:${progressCol};font-weight:700;font-size:.72rem">${progressLabel}</span></div>
    <div style="font-size:1.6rem;font-weight:900;color:${progressCol}">${adapt.gradeable}<span style="font-size:.85rem;color:var(--mut);font-weight:400"> / 100</span></div>
    <div class="prog-bar-track"><div class="prog-bar-fill" style="width:${progressPct}%;background:linear-gradient(90deg,${progressCol}88,${progressCol})"></div></div>
    <div class="milestone-row">
      <div class="ms-item"><div class="ms-dot" style="background:${adapt.gradeable>=30?'var(--grn)':'var(--mut)'}"></div><div class="ms-txt" style="color:${adapt.gradeable>=30?'var(--grn)':'var(--mut)'}">30</div><div class="ms-txt" style="color:var(--mut)">basic</div></div>
      <div class="ms-item"><div class="ms-dot" style="background:${adapt.gradeable>=100?'var(--grn)':'var(--mut)'}"></div><div class="ms-txt" style="color:${adapt.gradeable>=100?'var(--grn)':'var(--mut)'}">100</div><div class="ms-txt" style="color:var(--mut)">adaptive</div></div>
